// Calculate financial data by provider
const today = new Date();
today.setHours(0, 0, 0, 0);

const allBookings = items.map(item => item.json);

// Filter for today's completed bookings
const todayCompleted = allBookings.filter(booking => {
  const bookingDate = new Date(booking.tourDate);
  bookingDate.setHours(0, 0, 0, 0);
  return bookingDate.getTime() === today.getTime() && 
         booking.status === 'completed';
});

// Group by provider and calculate finances
const providerFinances = {};

todayCompleted.forEach(booking => {
  const providerId = booking.providerId || booking.providerName;
  const amount = parseFloat(booking.totalAmount) || 0;
  const commissionRate = parseFloat(booking.commissionRate) || 0.15; // 15% default

  if (!providerFinances[providerId]) {
    providerFinances[providerId] = {
      providerId: providerId,
      providerName: booking.providerName,
      providerEmail: booking.providerEmail,
      providerLineId: booking.providerLineId,
      commissionRate: commissionRate * 100,
      paymentTerms: booking.paymentTerms || 'weekly',
      currency: booking.currency || 'USD',
      completedTours: 0,
      totalCustomers: 0,
      totalRevenue: 0,
      commissionAmount: 0,
      providerShare: 0,
      paymentBreakdown: {},
      tourDetails: []
    };
  }

  const provider = providerFinances[providerId];
  const commission = amount * commissionRate;

  provider.completedTours++;
  provider.totalCustomers += parseInt(booking.numberOfPeople) || 1;
  provider.totalRevenue += amount;
  provider.commissionAmount += commission;
  provider.providerShare += (amount - commission);

  // Payment method breakdown
  const paymentMethod = booking.paymentMethod || 'Unknown';
  if (!provider.paymentBreakdown[paymentMethod]) {
    provider.paymentBreakdown[paymentMethod] = {
      method: paymentMethod,
      count: 0,
      amount: 0
    };
  }
  provider.paymentBreakdown[paymentMethod].count++;
  provider.paymentBreakdown[paymentMethod].amount += amount;

  // Tour details
  provider.tourDetails.push({
    tourName: booking.tourName,
    pickupTime: booking.pickupTime,
    customerName: booking.customerName,
    numberOfPeople: booking.numberOfPeople,
    amount: amount.toFixed(2),
    paymentMethod: paymentMethod
  });
});

// Format results
const results = Object.values(providerFinances).map(provider => {
  // Determine settlement
  const settlementAmount = Math.abs(provider.commissionAmount);
  const owedToProvider = provider.providerShare > provider.commissionAmount;

  return {
    ...provider,
    totalRevenue: provider.totalRevenue.toFixed(2),
    commissionAmount: provider.commissionAmount.toFixed(2),
    providerShare: provider.providerShare.toFixed(2),
    averageRevenue: (provider.totalRevenue / provider.completedTours).toFixed(2),
    paymentBreakdown: Object.values(provider.paymentBreakdown).map(pb => ({
      ...pb,
      amount: pb.amount.toFixed(2)
    })),
    settlementAmount: settlementAmount.toFixed(2),
    owedToProvider: owedToProvider,
    date: today.toLocaleDateString('en-US', { 
      weekday: 'long', 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    }),
    reportGeneratedTime: new Date().toLocaleString(),
    // Week-to-date placeholder (would calculate from historical data)
    weekRevenue: provider.totalRevenue,
    weekTours: provider.completedTours,
    averageDailyRevenue: (provider.totalRevenue / 1).toFixed(2)
  };
});

return results.map(r => ({ json: r }));

