// Create comprehensive admin financial summary
const allProviders = items.map(item => item.json);

const totalRevenue = allProviders.reduce((sum, p) => parseFloat(p.totalRevenue) + sum, 0);
const totalCommissions = allProviders.reduce((sum, p) => parseFloat(p.commissionAmount) + sum, 0);
const totalTours = allProviders.reduce((sum, p) => p.completedTours + sum, 0);
const totalCustomers = allProviders.reduce((sum, p) => p.totalCustomers + sum, 0);

const summary = {
  date: allProviders[0]?.date || new Date().toLocaleDateString(),
  currency: allProviders[0]?.currency || 'USD',
  totalRevenue: totalRevenue.toFixed(2),
  totalCommissions: totalCommissions.toFixed(2),
  netRevenue: (totalRevenue - totalCommissions).toFixed(2),
  totalTours: totalTours,
  totalCustomers: totalCustomers,
  averageRevenuePerTour: (totalRevenue / totalTours).toFixed(2),
  totalProviders: allProviders.length,
  providerBreakdown: allProviders.map(p => ({
    name: p.providerName,
    revenue: p.totalRevenue,
    commission: p.commissionAmount,
    tours: p.completedTours,
    customers: p.totalCustomers,
    settlement: p.settlementAmount,
    owedToProvider: p.owedToProvider
  })),
  reportGeneratedTime: new Date().toLocaleString()
};

return [{ json: summary }];
